using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut;

    public OrderServiceTests()
    {
        _sut = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    #region CreateOrder – happy path

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectCustomerId()
    {
        // Arrange
        var items = CreateItems(("Widget", 9.99m, 1));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_AssignsNonEmptyId()
    {
        var items = CreateItems(("Widget", 9.99m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 9.99m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_StoresItemsOnOrder()
    {
        var items = CreateItems(("Widget", 9.99m, 2));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreSame(items, order.Items);
    }

    #endregion

    #region CreateOrder – total calculation

    [TestMethod]
    public void CreateOrder_SingleItem_CalculatesTotalAsPriceTimesQuantity()
    {
        var items = CreateItems(("Widget", 10.00m, 3));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(30.00m, order.Total);
    }

    [TestMethod]
    [DynamicData(nameof(MultiItemTestData))]
    public void CreateOrder_MultipleItems_CalculatesTotalCorrectly(
        (string name, decimal price, int qty)[] itemDefs, decimal expectedTotal)
    {
        var items = CreateItems(itemDefs);

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(expectedTotal, order.Total);
    }

    public static IEnumerable<((string, decimal, int)[] items, decimal expectedTotal)> MultiItemTestData =>
    [
        (new[] { ("A", 5.00m, 2), ("B", 3.50m, 4) }, 24.00m),   // 10 + 14
        (new[] { ("X", 0.01m, 1), ("Y", 99.99m, 1) }, 100.00m), // boundary prices
        (new[] { ("Z", 25.00m, 1) }, 25.00m),                    // single item via DynamicData
    ];

    #endregion

    #region CreateOrder – validation

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 9.99m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsMatchingOrder()
    {
        var items = CreateItems(("Widget", 5.00m, 1));
        var created = _sut.CreateOrder("cust-1", items);

        var found = _sut.GetOrder(created.Id);

        Assert.AreSame(created, found);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var result = _sut.GetOrdersByCustomer("cust-unknown");

        Assert.IsNotNull(result);
        Assert.IsEmpty(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_OneOrder_ReturnsSingleOrder()
    {
        var items = CreateItems(("Widget", 5.00m, 1));
        var created = _sut.CreateOrder("cust-1", items);

        var result = _sut.GetOrdersByCustomer("cust-1");

        var single = Assert.ContainsSingle(result);
        Assert.AreSame(created, single);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAllForCustomer()
    {
        _sut.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
        _sut.CreateOrder("cust-1", CreateItems(("B", 2m, 1)));
        _sut.CreateOrder("cust-2", CreateItems(("C", 3m, 1)));

        var result = _sut.GetOrdersByCustomer("cust-1");

        Assert.HasCount(2, result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_DoesNotReturnOtherCustomerOrders()
    {
        _sut.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
        _sut.CreateOrder("cust-2", CreateItems(("B", 2m, 1)));

        var result = _sut.GetOrdersByCustomer("cust-1");

        Assert.IsTrue(result.All(o => o.CustomerId == "cust-1"));
    }

    #endregion

    #region CreateOrder – uniqueness

    [TestMethod]
    public void CreateOrder_CalledTwice_AssignsUniqueIds()
    {
        var items = CreateItems(("Widget", 1m, 1));

        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    #endregion
}

